import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.c3r8iWL8.js";const m=JSON.parse('{"title":"SOP-007: Incident Response","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-007-incident-response.md","filePath":"sops/SOP-007-incident-response.md","lastUpdated":1782929962000}'),o={name:"sops/SOP-007-incident-response.md"};function n(s,t,d,l,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="sop-007-incident-response" tabindex="-1">SOP-007: Incident Response <a class="header-anchor" href="#sop-007-incident-response" aria-label="Permalink to &quot;SOP-007: Incident Response&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> SRE · <strong>Gate:</strong> G4</p><blockquote><p><strong>Decision guide:</strong> <a href="./../guides/incident-management.html">Incident management</a> · <a href="./../guides/monitoring-tracing-logging.html">Monitoring &amp; tracing</a> · <a href="./../guides/dashboards-reporting.html">Dashboards</a></p></blockquote><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Detect, triage, mitigate, and communicate production incidents. AI assists correlation and draft comms; humans own mitigation decisions.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>SRE (on-call)</td><td><strong>A/R</strong> — incident commander</td></tr><tr><td>DEV</td><td>R — fix deployment</td></tr><tr><td>ARCH</td><td>C — architectural mitigation</td></tr><tr><td>SEC</td><td>C — security incidents</td></tr><tr><td>PO</td><td>I — customer comms input</td></tr></tbody></table><h2 id="severity-definitions" tabindex="-1">Severity definitions <a class="header-anchor" href="#severity-definitions" aria-label="Permalink to &quot;Severity definitions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sev</th><th>Criteria</th><th>Response</th></tr></thead><tbody><tr><td><strong>1</strong></td><td>T1 outage or data breach</td><td>Page immediately; war room</td></tr><tr><td><strong>2</strong></td><td>T2 degraded SLO</td><td>Page on-call; ticket</td></tr><tr><td><strong>3</strong></td><td>T3 / non-customer impact</td><td>Ticket next business day</td></tr><tr><td><strong>4</strong></td><td>Cosmetic / low risk</td><td>Backlog</td></tr></tbody></table><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><h3 id="detect-acknowledge" tabindex="-1">Detect &amp; acknowledge <a class="header-anchor" href="#detect-acknowledge" aria-label="Permalink to &quot;Detect &amp; acknowledge&quot;">​</a></h3><ol><li><strong>Alert fires</strong> — CloudWatch, Synthetics, GuardDuty, or deploy metric gate.</li><li><strong>Acknowledge</strong> — On-call ack in PagerDuty within SLA (T1: 15 min).</li><li><strong>Auto-enrichment</strong> — EventBridge Lambda attaches: recent deploys, trace samples, AI-drafted summary (hypothesis labeled).</li></ol><h3 id="triage" tabindex="-1">Triage <a class="header-anchor" href="#triage" aria-label="Permalink to &quot;Triage&quot;">​</a></h3><ol start="4"><li><strong>Classify severity</strong> — Use table above; escalate Sev-1 to EM + ARCH within 1h.</li><li><strong>Correlate deploy</strong> — If alert within 30 min of deploy → consider rollback (<a href="./SOP-006-release-deploy.html">SOP-006</a>).</li><li><strong>AI log analysis</strong> — Use OpenSearch ML / Bedrock for pattern clustering; <strong>human validates</strong> root cause hypothesis.</li></ol><h3 id="mitigate" tabindex="-1">Mitigate <a class="header-anchor" href="#mitigate" aria-label="Permalink to &quot;Mitigate&quot;">​</a></h3><ol start="7"><li><strong>Mitigate first</strong> — Rollback, scale, feature flag off, traffic shift — before deep debugging.</li><li><strong>Communicate</strong> — Status page + internal Slack; PO consulted for external messaging (Sev-1/2).</li><li><strong>Document</strong> — Incident ticket with timeline, actions, current status.</li></ol><h3 id="resolve" tabindex="-1">Resolve <a class="header-anchor" href="#resolve" aria-label="Permalink to &quot;Resolve&quot;">​</a></h3><ol start="10"><li><strong>Verify</strong> — SLOs green; canaries pass 30 min.</li><li><strong>Close incident</strong> — Hand off to <a href="./SOP-008-post-incident.html">SOP-008</a> for Sev-1/2.</li></ol><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] Service restored to SLO</li><li>[ ] Incident ticket complete with timeline</li><li>[ ] Stakeholders notified</li><li>[ ] Sev-1/2 → SOP-008 initiated</li></ul><h2 id="sla" tabindex="-1">SLA <a class="header-anchor" href="#sla" aria-label="Permalink to &quot;SLA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sev</th><th>Ack</th><th>Mitigation target</th></tr></thead><tbody><tr><td>1</td><td>15 min</td><td>1 h to mitigate or rollback</td></tr><tr><td>2</td><td>30 min</td><td>4 h</td></tr><tr><td>3</td><td>4 h</td><td>2 business days</td></tr></tbody></table><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-006-release-deploy.html">SOP-006</a> · <a href="./SOP-008-post-incident.html">SOP-008</a> · <a href="./../cicd-observability.html">cicd-observability.md</a></li></ul>',24)])])}const p=e(o,[["render",n]]);export{m as __pageData,p as default};
